"""Simple SQL query builder."""

class Query:
    def __init__(self, table):
        self.table = table
        self._select = ["*"]
        self._where = []
        self._order_by = []
        self._limit = None
        self._offset = None
        self._joins = []
        self._params = []

    def select(self, *columns):
        self._select = list(columns)
        return self

    def where(self, condition, *params):
        self._where.append(condition)
        self._params.extend(params)
        return self

    def order_by(self, column, desc=False):
        direction = "DESC" if desc else "ASC"
        self._order_by.append(f"{column} {direction}")
        return self

    def limit(self, n):
        self._limit = n
        return self

    def offset(self, n):
        self._offset = n
        return self

    def join(self, table, on):
        self._joins.append(f"JOIN {table} ON {on}")
        return self

    def build(self):
        """Build SQL string and params."""
        parts = [f"SELECT {', '.join(self._select)} FROM {self.table}"]

        for j in self._joins:
            parts.append(j)

        if self._where:
            parts.append(f"WHERE {' AND '.join(self._where)}")

        if self._order_by:
            parts.append(f"ORDER BY {', '.join(self._order_by)}")

        # Bug: LIMIT and OFFSET in wrong order (OFFSET should come after LIMIT in SQL)
        if self._offset is not None:
            parts.append(f"OFFSET {self._offset}")
        if self._limit is not None:
            parts.append(f"LIMIT {self._limit}")

        return ' '.join(parts), self._params

    def count(self):
        """Build COUNT query."""
        parts = [f"SELECT COUNT(*) FROM {self.table}"]
        for j in self._joins:
            parts.append(j)
        if self._where:
            parts.append(f"WHERE {' AND '.join(self._where)}")
        return ' '.join(parts), self._params

